import{_ as r,c as i,o,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.2.2: Major Session List Performance Improvement","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.2.2.md","filePath":"en/changelog/v1.2.2.md","lastUpdated":1772014034000}'),s={name:"en/changelog/v1.2.2.md"};function n(l,a,d,h,c,p){return o(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-2-2-major-session-list-performance-improvement" tabindex="-1">v1.2.2: Major Session List Performance Improvement <a class="header-anchor" href="#v1-2-2-major-session-list-performance-improvement" aria-label="Permalink to “v1.2.2: Major Session List Performance Improvement”">​</a></h1><p><strong>Release Date</strong>: February 14, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update makes <strong>session list loading much faster</strong>, especially noticeable when you have many sessions.</p><hr><h2 id="new-feature-session-list-performance-optimization" tabindex="-1">New Feature: Session List Performance Optimization <a class="header-anchor" href="#new-feature-session-list-performance-optimization" aria-label="Permalink to “New Feature: Session List Performance Optimization”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Optimized <code>Session.list()</code> query performance by filtering at the database level instead of loading all data first and then filtering.</p><h3 id="what-is-the-session-list" tabindex="-1">What is the session list? <a class="header-anchor" href="#what-is-the-session-list" aria-label="Permalink to “What is the session list?”">​</a></h3><p>OpenCode saves all historical sessions. When you run <code>opencode attach</code> or view the session list in different project directories, OpenCode needs to load these historical records.</p><h3 id="how-big-is-the-performance-improvement" tabindex="-1">How big is the performance improvement? <a class="header-anchor" href="#how-big-is-the-performance-improvement" aria-label="Permalink to “How big is the performance improvement?”">​</a></h3><table tabindex="0"><thead><tr><th>Number of Sessions</th><th>Before</th><th>Now</th></tr></thead><tbody><tr><td>10</td><td>Fast</td><td>Fast</td></tr><tr><td>50</td><td>Slower</td><td>Fast</td></tr><tr><td>100+</td><td>Noticeable lag</td><td>Smooth</td></tr></tbody></table><p><strong>Simply put</strong>: If you have many sessions (dozens to hundreds), this update will make things feel &quot;much faster.&quot;</p><hr><h2 id="bug-fix-model-variant-support" tabindex="-1">Bug Fix: Model Variant Support <a class="header-anchor" href="#bug-fix-model-variant-support" aria-label="Permalink to “Bug Fix: Model Variant Support”">​</a></h2><h3 id="the-previous-problem" tabindex="-1">The Previous Problem <a class="header-anchor" href="#the-previous-problem" aria-label="Permalink to “The Previous Problem”">​</a></h3><p>When using Vercel gateway or certain providers, model variants might not be correctly identified and used.</p><h3 id="the-current-situation" tabindex="-1">The Current Situation <a class="header-anchor" href="#the-current-situation" aria-label="Permalink to “The Current Situation”">​</a></h3><p>Fixed the Vercel gateway variant issue, ensuring more accurate model selection.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Many sessions, loading is slow</td><td>✅ Upgrade</td></tr><tr><td>Using Vercel gateway</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next release</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',24),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-optional" tabindex="-1">Technical Details (Optional) <a class="header-anchor" href="#technical-details-optional" aria-label="Permalink to “Technical Details (Optional)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Added comprehensive test coverage for Session.list() filters</li><li>Filter sessions at database level to improve session list loading performance</li><li>Fixed Vercel gateway variants</li><li>Upgraded Vertex AI package</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const f=r(s,[["render",n]]);export{u as __pageData,f as default};
